#include <stdio.h>

int main(void) {
    double x1, y1, x2, y2;
    if (scanf("%lf %lf %lf %lf", &x1, &y1, &x2, &y2) != 4) return 0;
    double a = y1 - y2;
    double b = x2 - x1;
    double c = a * x1 + b * y1;
    printf("line: %.3fx + %.3fy = %.3f\n", a, b, c);
    return 0;
}
